function getText() {
  if (message && message.contact && message.contact.phone_number) {
    return String(message.contact.phone_number);
  }
  if (message && message.text) {
    return String(message.text).trim();
  }
  return "";
}

function cleanupInternal() {
  delete_context("_quote_step");
}

function ask(prompt) {
  send_message({ text: prompt, parse_mode: "HTML" });
}

var steps = [
  {
    key: "quote_name",
    prompt: get_context("param_name_prompt") || "Taklif so'rovi uchun ism yoki kompaniya nomini yozing:",
    error: "Kamida 2 ta belgidan iborat nom yuboring.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "quote_need",
    prompt: get_context("param_need_prompt") || "Qaysi xizmat yoki mahsulot bo'yicha taklif kerak?",
    error: "So'rov mavzusini kiriting.",
    validate: function(value) { return value.length >= 3; }
  },
  {
    key: "quote_budget",
    prompt: get_context("param_budget_prompt") || "Taxminiy budjet yoki diapazonni yozing. Bilmasangiz '-' deb yuboring.",
    error: "Javobni qayta yuboring.",
    validate: function(value) { return value.length >= 1; },
    normalize: function(value) {
      if (value === "-") return "";
      return value;
    }
  },
  {
    key: "quote_timeline",
    prompt: get_context("param_timeline_prompt") || "Qachongacha kerakligini yozing. Masalan: tez orada, 1 hafta ichida",
    error: "Muddatni kiriting.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "quote_phone",
    prompt: get_context("param_phone_prompt") || "Bog'lanish uchun telefon raqamingizni yuboring:",
    error: "Telefon raqamini +998901234567 formatida kiriting yoki kontakt yuboring.",
    validate: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      return /^\+?\d{9,15}$/.test(cleaned);
    },
    normalize: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      if (cleaned[0] !== "+") return "+" + cleaned;
      return cleaned;
    }
  }
];

var step = parseInt(get_context("_quote_step") || "0", 10);
var answer = getText();

if (answer.toLowerCase() === "/cancel") {
  cleanupInternal();
  exit("cancelled");
}

if (step > 0) {
  var previous = steps[step - 1];
  var value = answer;
  if (previous.normalize) value = previous.normalize(value);
  if (!previous.validate(value)) {
    ask(previous.error + "\n\nBekor qilish uchun /cancel yuboring.");
    wait_for_input();
  }
  set_context(previous.key, value);
}

if (step >= steps.length) {
  var successMessage = get_context("param_success_message") || (
    "<b>Taklif so'rovi qabul qilindi.</b>\n\n" +
    "🏢 Mijoz: " + (get_context("quote_name") || "") + "\n" +
    "🧩 So'rov: " + (get_context("quote_need") || "") + "\n" +
    "💸 Budjet: " + (get_context("quote_budget") || "-") + "\n" +
    "⏱ Muddat: " + (get_context("quote_timeline") || "") + "\n" +
    "📞 Telefon: " + (get_context("quote_phone") || "")
  );
  send_message({ text: successMessage, parse_mode: "HTML" });
  cleanupInternal();
  exit("completed");
}

ask(steps[step].prompt + "\n\nBekor qilish uchun /cancel yuboring.");
set_context("_quote_step", String(step + 1));
wait_for_input();
